mapper.select:
SELECT nh.hid, nh.title, nh.type, nu.nick_name, nh.page_views AS pageViews, TIMESTAMPDIFF(HOUR, create_time, NOW()) as pastHour FROM news_headline AS nh left join news_user as nu on nu.uid = nh.publisher WHERE is_deleted = 0
AND title LIKE CONCAT('%',#{request.keyWord},'%')
AND type = #{request.type}
AND nh.publisher = #{request.uid}
ORDER BY nh.update_time desc
